import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

export default function ProjectDetails() {
  const { id } = useParams();
  const { user } = useAuth();
  const [project, setProject] = useState(null);
  const [loading, setLoading] = useState(true);
  const [amount, setAmount] = useState('');
  const [message, setMessage] = useState('');
  const [contributing, setContributing] = useState(false);

  useEffect(() => {
    axios.get(`/api/projects/${id}`)
      .then(r => setProject(r.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [id]);

  const handleContribute = async () => {
    if (!amount || Number(amount) <= 0) return toast.error('Please enter a valid amount');
    setContributing(true);
    try {
      await axios.post('/api/contributions', { projectId: id, amount: Number(amount), message });
      toast.success(`🎉 Thanks for backing $${amount}!`);
      setAmount('');
      setMessage('');
      // Refresh project
      const r = await axios.get(`/api/projects/${id}`);
      setProject(r.data);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Contribution failed');
    } finally {
      setContributing(false);
    }
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center text-gray-400" style={{ background: '#0a0d1a' }}>Loading...</div>;
  if (!project) return <div className="min-h-screen flex items-center justify-center text-gray-400" style={{ background: '#0a0d1a' }}>Project not found</div>;

  const pct = Math.min(Math.round((project.currentFunding / project.fundingGoal) * 100), 100);
  const daysLeft = project.deadline ? Math.max(0, Math.ceil((new Date(project.deadline) - new Date()) / (1000 * 60 * 60 * 24))) : null;

  return (
    <div style={{ background: '#0a0d1a', minHeight: '100vh' }} className="px-6 py-10">
      <div className="max-w-5xl mx-auto">
        <div className="grid grid-cols-3 gap-8">
          {/* Main content */}
          <div className="col-span-2">
            {project.coverImage ? (
              <img src={project.coverImage} alt={project.title} className="w-full h-64 object-cover rounded-2xl mb-6" />
            ) : (
              <div style={{ background: 'linear-gradient(135deg, #1f2937, #111827)', height: 256 }}
                   className="rounded-2xl mb-6 flex items-center justify-center text-6xl">
                {project.category === 'Technology' ? '💻' : project.category === 'Health' ? '🏥' : '✦'}
              </div>
            )}

            <span style={{ background: '#1f2937', color: '#9ca3af' }}
                  className="text-xs px-3 py-1 rounded-full mb-3 inline-block">{project.category}</span>
            <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-3xl font-bold mb-3">{project.title}</h1>
            <p className="text-gray-400 text-sm mb-2">by {project.innovator?.name}</p>

            <p className="text-gray-300 leading-relaxed mt-6">{project.description}</p>

            <div className="grid grid-cols-3 gap-4 mt-8">
              {[
                { label: 'Team Size', value: `${project.teamSize} people` },
                { label: 'Timeline', value: project.timeline },
                { label: 'Category', value: project.category },
              ].map(s => (
                <div key={s.label} style={{ background: '#111827', border: '1px solid #1f2937' }}
                     className="p-4 rounded-xl text-center">
                  <div className="font-semibold text-sm">{s.value}</div>
                  <div className="text-gray-500 text-xs mt-1">{s.label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Sidebar */}
          <div className="space-y-4">
            {/* Funding card */}
            <div style={{ background: '#111827', border: '1px solid #1f2937' }} className="p-6 rounded-2xl">
              <div style={{ fontFamily: 'Syne, sans-serif', color: '#00d4aa' }} className="text-3xl font-black mb-1">
                ${project.currentFunding?.toLocaleString()}
              </div>
              <div className="text-gray-400 text-sm mb-4">pledged of ${project.fundingGoal?.toLocaleString()} goal</div>

              <div style={{ background: '#0a0d1a', height: 8, borderRadius: 4 }} className="mb-3">
                <div style={{ background: '#00d4aa', width: `${pct}%`, height: '100%', borderRadius: 4 }} />
              </div>
              <div className="flex justify-between text-sm mb-4">
                <span style={{ color: '#00d4aa' }} className="font-bold">{pct}%</span>
                {daysLeft !== null && <span className="text-gray-400">{daysLeft} days left</span>}
              </div>
              <div className="text-gray-500 text-sm">{project.backers?.length || 0} backers</div>
            </div>

            {/* Contribute form (backers only) */}
            {user?.role === 'backer' && (
              <div style={{ background: '#111827', border: '1px solid #1f2937' }} className="p-5 rounded-2xl">
                <h3 className="font-semibold mb-4">Back this project</h3>
                <input type="number" value={amount} onChange={e => setAmount(e.target.value)} min={1}
                  style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
                  className="w-full px-4 py-3 rounded-xl text-sm mb-3 focus:outline-none focus:border-teal-500"
                  placeholder="Amount ($)" />
                <textarea value={message} onChange={e => setMessage(e.target.value)} rows={2}
                  style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
                  className="w-full px-4 py-3 rounded-xl text-sm mb-3 focus:outline-none focus:border-teal-500"
                  placeholder="Leave a message (optional)" />
                <button onClick={handleContribute} disabled={contributing}
                  style={{ background: '#00d4aa', color: '#0a0d1a' }}
                  className="w-full py-3 rounded-xl font-bold text-sm hover:opacity-90 transition-all disabled:opacity-60">
                  {contributing ? 'Processing...' : `Back for $${amount || '...'}`}
                </button>
              </div>
            )}

            {/* AI Evaluation */}
            {project.aiEvaluation?.feasibilityScore !== null && (
              <div style={{ background: '#111827', border: '1px solid rgba(0,212,170,0.2)' }} className="p-5 rounded-2xl">
                <p style={{ color: '#00d4aa' }} className="text-xs font-bold uppercase tracking-wider mb-4">
                  ✦ Gemini AI Analysis
                </p>
                {[
                  { label: 'Feasibility', score: project.aiEvaluation.feasibilityScore },
                  { label: 'Success Prob.', score: project.aiEvaluation.successProbability }
                ].map(s => {
                  const color = s.score >= 70 ? '#10b981' : s.score >= 40 ? '#f59e0b' : '#ef4444';
                  return (
                    <div key={s.label} className="mb-3">
                      <div className="flex justify-between text-xs mb-1.5">
                        <span className="text-gray-400">{s.label}</span>
                        <span style={{ color }} className="font-bold">{s.score}/100</span>
                      </div>
                      <div style={{ background: '#0a0d1a', height: 6, borderRadius: 3 }}>
                        <div style={{ background: color, width: `${s.score}%`, height: '100%', borderRadius: 3 }} />
                      </div>
                    </div>
                  );
                })}
                <p className="text-gray-400 text-xs leading-relaxed mt-3">{project.aiEvaluation.explanation}</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
